query:
-- Contar usuários de teste
SELECT COUNT(*) as test_users FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%';

-- Contar bolões de teste (dos usuários de teste)
SELECT COUNT(*) as test_pools FROM pools WHERE ownerId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- Contar palpites de teste
SELECT COUNT(*) as test_bets FROM bets WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- Contar badges de teste
SELECT COUNT(*) as test_badges FROM user_badges WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

